def solve(data: str) -> str:
    n = int(data.strip())
    rows = []
    row = [1]
    for _ in range(n):
        rows.append(' '.join(map(str, row)))
        new = [1]
        for i in range(len(row)-1):
            new.append(row[i]+row[i+1])
        new.append(1)
        row = new
    return '\n'.join(rows)


def __main__():
    import sys
    data = sys.stdin.read()
    result = solve(data)
    if result is None:
        return
    sys.stdout.write(str(result))

if __name__ == '__main__':
    __main__()

