import java.io.*;
import java.nio.charset.StandardCharsets;

public class Main {
static class Solution {
    public String solve(String data){
        data = data.trim();
        if(data.isEmpty()) return "";
        int n = Integer.parseInt(data);
        java.util.List<Long> row = new java.util.ArrayList<>();
        row.add(1L);
        StringBuilder sb = new StringBuilder();
        for(int r=0;r<n;r++){
            for(int i=0;i<row.size();i++){ if(i>0) sb.append(' '); sb.append(row.get(i)); }
            if(r!=n-1) sb.append('\n');
            java.util.List<Long> nxt = new java.util.ArrayList<>(row.size()+1);
            nxt.add(1L);
            for(int i=1;i<row.size();i++) nxt.add(row.get(i-1)+row.get(i));
            nxt.add(1L);
            row = nxt;
        }
        return sb.toString();
    }
}


    public static void main(String[] args) throws Exception {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        InputStream in = System.in;
        byte[] buf = new byte[8192];
        int n;
        while ((n = in.read(buf)) != -1) {
            baos.write(buf, 0, n);
        }
        String input = baos.toString(StandardCharsets.UTF_8);
        Solution sol = new Solution();
        String output = sol.solve(input);
        if (output != null) {
            System.out.print(output);
        }
    }
}

