#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_INPUT (1 << 20)

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
char* solve(const char* data){
    int n = atoi(data);
    long long row[64];
    long long nxt[64];
    int pos=0; int buf=10000;
    char* out = malloc(buf);
    row[0]=1; int len=1;
    for(int r=0;r<n;r++){
        for(int i=0;i<len;i++){
            if(pos+32 >= buf){ buf*=2; out=realloc(out, buf); }
            if(i) out[pos++]=' ';
            pos += sprintf(out+pos, "%lld", row[i]);
        }
        if(r!=n-1) out[pos++]='\n';
        nxt[0]=1; nxt[len]=1;
        for(int i=1;i<len;i++) nxt[i]=row[i-1]+row[i];
        memcpy(row,nxt,sizeof(long long)*(len+1));
        len++;
    }
    out[pos]='\0';
    return out;
}


int main() {
    char *input = (char *)malloc(MAX_INPUT);
    if (!input) return 1;
    size_t len = fread(input, 1, MAX_INPUT - 1, stdin);
    input[len] = '\0';
    char *output = solve(input);
    if (output) {
        fputs(output, stdout);
        free(output);
    }
    free(input);
    return 0;
}
